fn resize_rgb_nn(
    src: &[[f32; 3]],
    sw: usize,
    sh: usize,
    dw: usize,
    dh: usize,
) -> Vec<[f32; 3]> {
    let mut dst = vec![[0.0_f32; 3]; dw * dh];
    for dy in 0..dh {
        for dx in 0..dw {
            let sx = ((dx as f32 * sw as f32) / dw as f32) as usize;
            let sy = ((dy as f32 * sh as f32) / dh as f32) as usize;
            let sx = sx.min(sw - 1);
            let sy = sy.min(sh - 1);
            dst[dy * dw + dx] = src[sy * sw + sx];
        }
    }
    dst
}
